#include <bits/stdc++.h>
using namespace std;
long long a[4];
int main(){
    long long n,b=0;
    cin>>n;
    string c;
    for(int i=0;i<n;i++){
        cin>>c;
        if(c[0]=='M'){
            a[0]++;
        }
        else if(c[0]=='C')
        {
            a[1]++;
        }
        else if(c[0]=='O'){
            a[2]++;
        }
        else if(c[0]=='I'){
            a[3]++;
        }
    }
    b+=a[0]*a[1]*a[2];
    b+=a[0]*a[1]*a[3];
    b+=a[0]*a[2]*a[3];
    b+=a[1]*a[2]*a[3];
    cout<<b;
    return 0;
}
